107					knex,
108					userId: user._id,
109					companyId: company._id,
110					role: 'admin',
111				});
112	
113				const sessionId = randomUUID();
114				await createSession({
115					redis,
116					userId: user._id,
117					sessionId,
118					role: 'admin',
119					companyId: company._id,
