635				await request(httpServer)
636					.post('/api/integrations/github/webhook')
637					.set('Content-Type', 'text/plain')
638					.set('x-github-event', 'installation')
639					.set('x-hub-signature-256', deleteSig)
640					.set('x-github-hook-installation-target-id', '22222222')
641					.send(deleteBody);
642	
643				const pushBody = '{"ref":"refs/heads/main"}';
644				const pushSig = `sha256=${createHmac('sha256', secret).update(pushBody).digest('hex')}`;
645	
646				const res = await request(httpServer)
647					.post('/api/integrations/github/webhook')
648					.set('Content-Type', 'text/plain')
649					.set('x-github-event', 'push')
650					.set('x-hub-signature-256', pushSig)
651					.set('x-github-hook-installation-target-id', '22222222')
652					.send(pushBody);
653	
654				expect(res.status).toBe(200);
655			});
656		});
657	});
