38		async exchangeCode({ code }: { code: string }): Promise<IAtlassianTokenResponse> {
39			const { data } = await this.httpService.axiosRef.post<IAtlassianTokenResponse>(
40				ATLASSIAN_TOKEN_URL,
41				{
42					grant_type: 'authorization_code',
43					client_id: this.configService.get<string>({ key: JIRA_CLIENT_ID }),
44					client_secret: this.configService.get<string>({ key: JIRA_CLIENT_SECRET }),
45					redirect_uri: this.configService.get<string>({ key: JIRA_CALLBACK_URL }),
46					code,
47				},
48			);
49			return data;
50		}
51	
52		async getAccessibleResources({
53			accessToken,
54		}: {
55			accessToken: string;
56		}): Promise<IAtlassianResource[]> {
57			const { data } = await this.httpService.axiosRef.get<IAtlassianResource[]>(
58				ATLASSIAN_RESOURCES_URL,
59				{ headers: { Authorization: `Bearer ${accessToken}` } },
60			);
61			return data;
62		}
63	
64		async getValidToken({
65			installation,
66		}: {
67			installation: IJiraInstallationBase;
68		}): Promise<string> {
69			const expiresAt = new Date(installation.token_expires_at).getTime();
70			const now = Date.now();
71	
72			if (expiresAt - now > TOKEN_REFRESH_BUFFER_MS) {
73				return installation.access_token;
74			}
75	
76			try {
77				const refreshed = await this.refreshToken({
78					refreshToken: installation.refresh_token,
79				});
80	
81				const tokenExpiresAt = new Date(Date.now() + refreshed.expires_in * 1000);
82	
83				await this.installationModel.updateTokens({
84					id: installation._id,
85					accessToken: refreshed.access_token,
86					refreshToken: refreshed.refresh_token,
87					tokenExpiresAt,
88				});
89	
90				this.logger.debug(`Refreshed token for installation ${installation._id}`);
91				return refreshed.access_token;
92			} catch (error) {
93				await this.installationModel.markNeedsReauth({ id: installation._id });
94				this.logger.error(
95					`Token refresh failed for installation ${installation._id}: ${(error as Error).message}`,
96				);
97				throw error;
98			}
99		}
