30		) {}
31	
32		async discoverProjects({
33			installationDbId,
34		}: {
35			installationDbId: string;
36		}): Promise<void> {
37			const installation = await this.installationModel.findById({ id: installationDbId });
38	
39			if (!installation) {
40				this.logger.warn(`Installation ${installationDbId} not found`);
41				return;
42			}
43	
44			const token = await this.jiraApiService.getValidToken({ installation });
45			const projects = await this.jiraApiService.listProjects({
46				cloudId: installation.cloud_id,
47				token,
48			});
49	
50			await this.projectModel.upsertMany({ installationId: installationDbId, projects });
51	
52			const savedProjects = await this.projectModel.findByInstallationId({
53				installationId: installationDbId,
54			});
55	
56			for (const project of savedProjects) {
57				await this.jiraQueue.add(
58					'sync_project',
59					{
60						installationDbId,
61						projectDbId: project._id,
62						projectKey: project.project_key,
63						projectId: project.project_id,
64					},
65					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
66				);
67			}
68	
69			this.logger.debug(
70				`Enqueued sync for ${savedProjects.length} projects in installation ${installationDbId}`,
71			);
72		}
73	
74		async syncProject({
75			installationDbId,
76			projectDbId,
77			projectKey,
78		}: {
79			installationDbId: string;
80			projectDbId: string;
81			projectKey: string;
82		}): Promise<void> {
83			const installation = await this.installationModel.findById({ id: installationDbId });
84	
85			if (!installation) {
86				this.logger.warn(`Installation ${installationDbId} not found`);
87				return;
88			}
89	
90			const projects = await this.projectModel.findByInstallationId({
91				installationId: installationDbId,
92			});
93			const project = projects.find((p) => p._id === projectDbId);
94	
95			if (!project) {
96				this.logger.warn(`Project ${projectDbId} not found`);
97				return;
98			}
99	
100			const token = await this.jiraApiService.getValidToken({ installation });
101	
102			const since = project.last_synced_at ?? new Date(Date.now() - THREE_YEARS_MS);
103	
104			const sinceStr = since.toISOString().split('T')[0] ?? since.toISOString();
105			const jql = `project = "${projectKey}" AND updated >= "${sinceStr}" ORDER BY updated ASC`;
106	
107			await this.fetchAndStoreIssues({
108				installationDbId,
109				projectDbId,
110				cloudId: installation.cloud_id,
111				token,
112				jql,
113			});
114	
115			await this.fetchAndStoreSprints({
116				installationDbId,
117				projectKey,
118				cloudId: installation.cloud_id,
119				token,
120			});
121	
122			await this.projectModel.updateLastSyncedAt({ id: projectDbId });
123	
124			this.logger.debug(
125				`Sync complete for project ${projectKey} in installation ${installationDbId}`,
126			);
127		}
128	
129		async pollAllInstallations(): Promise<void> {
130			const installations = await this.installationModel.findAllActive();
131	
132			for (const installation of installations) {
133				await this.jiraQueue.add(
134					'discover_projects',
135					{ installationDbId: installation._id },
136					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
137				);
138			}
139	
140			this.logger.debug(
141				`Triggered discover_projects for ${installations.length} active installations`,
142			);
143		}
144	
145		private async fetchAndStoreIssues({
146			installationDbId,
147			projectDbId,
148			cloudId,
149			token,
150			jql,
151		}: {
152			installationDbId: string;
153			projectDbId: string;
154			cloudId: string;
155			token: string;
156			jql: string;
157		}): Promise<void> {
158			let startAt = 0;
159			const pageSize = 100;
160	
161			while (true) {
162				const response = await this.jiraApiService.searchIssues({
163					cloudId,
164					token,
165					jql,
166					startAt,
167				});
168	
169				if (response.issues.length === 0) break;
170	
171				const savedIssues = await this.issueModel.upsertMany({
172					issues: response.issues.map((issue) => ({
173						installation_id: installationDbId,
174						project_id: projectDbId,
175						issue_key: issue.key,
176						issue_id: issue.id,
177						issue_type: issue.fields.issuetype?.name ?? null,
178						status: issue.fields.status?.name ?? null,
179						priority: issue.fields.priority?.name ?? null,
180						assignee_id: issue.fields.assignee?.accountId ?? null,
181						reporter_id: issue.fields.reporter?.accountId ?? null,
182						story_points: issue.fields.customfield_10016 ?? null,
183						updated_at: new Date(issue.fields.updated),
184						resolved_at: issue.fields.resolutiondate
185							? new Date(issue.fields.resolutiondate)
186							: null,
187					})),
188				});
189	
190				await this.storeChangelogs({
191					installationDbId,
192					issues: response.issues,
193					savedIssues,
194				});
195	
196				await this.storeWorklogs({
197					installationDbId,
198					cloudId,
199					token,
200					issues: response.issues,
201					savedIssues,
202				});
203	
204				startAt += pageSize;
205				if (startAt >= response.total || response.issues.length < pageSize) break;
206			}
207		}
208	
209		private async storeChangelogs({
210			installationDbId,
211			issues,
212			savedIssues,
213		}: {
214			installationDbId: string;
215			issues: IJiraApiIssue[];
216			savedIssues: IJiraIssueBase[];
217		}): Promise<void> {
218			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
219			const entries: {
220				issue_id: string;
221				installation_id: string;
222				jira_history_id: string;
223				author_id: string | null;
224				field: string;
225				from_value: string | null;
226				to_value: string | null;
227				changed_at: Date;
228			}[] = [];
229	
230			for (const issue of issues) {
231				const issueDbId = issueDbIdMap.get(issue.id);
232				if (!issueDbId || !issue.changelog) continue;
233	
234				for (const history of issue.changelog.histories) {
235					for (const item of history.items) {
236						entries.push({
237							issue_id: issueDbId,
238							installation_id: installationDbId,
239							jira_history_id: history.id,
240							author_id: history.author?.accountId ?? null,
241							field: item.field,
242							from_value: item.fromString,
243							to_value: item.toString,
244							changed_at: new Date(history.created),
245						});
246					}
247				}
248			}
249	
250			await this.changelogModel.upsertMany({ entries });
251		}
252	
253		private async storeWorklogs({
254			installationDbId,
255			cloudId,
256			token,
257			issues,
258			savedIssues,
259		}: {
260			installationDbId: string;
261			cloudId: string;
262			token: string;
263			issues: IJiraApiIssue[];
264			savedIssues: IJiraIssueBase[];
265		}): Promise<void> {
266			const issueDbIdMap = new Map(savedIssues.map((i) => [i.issue_id, i._id]));
267	
268			for (const issue of issues) {
269				const issueDbId = issueDbIdMap.get(issue.id);
270				if (!issueDbId) continue;
271	
272				const worklogs = await this.jiraApiService.getWorklogsForIssue({
273					cloudId,
274					token,
275					issueId: issue.id,
276				});
277	
278				if (worklogs.length === 0) continue;
279	
280				await this.worklogModel.upsertMany({
281					worklogs: worklogs.map((w) => ({
282						issue_id: issueDbId,
283						installation_id: installationDbId,
284						jira_worklog_id: w.id,
285						author_id: w.author?.accountId ?? null,
286						time_spent_sec: w.timeSpentSeconds,
287						started_at: w.started ? new Date(w.started) : null,
288						updated_at: new Date(w.updated),
289					})),
290				});
291			}
292		}
293	
294		private async fetchAndStoreSprints({
295			installationDbId,
296			projectKey,
297			cloudId,
298			token,
299		}: {
300			installationDbId: string;
301			projectKey: string;
302			cloudId: string;
303			token: string;
304		}): Promise<void> {
305			try {
306				const boardsResponse = await this.jiraApiService.listBoards({
307					cloudId,
308					token,
309					projectKeyOrId: projectKey,
310				});
311	
312				for (const board of boardsResponse.values) {
313					let startAt = 0;
314					while (true) {
315						const sprintResponse = await this.jiraApiService.listSprints({
316							cloudId,
317							token,
318							boardId: board.id,
319							startAt,
320						});
321	
322						await this.sprintModel.upsertMany({
323							installationId: installationDbId,
324							boardId: String(board.id),
325							sprints: sprintResponse.values,
326						});
327	
328						if (sprintResponse.values.length === 0 || sprintResponse.isLast) break;
329						startAt += 50;
330					}
331				}
332			} catch (error) {
333				this.logger.warn(
334					`Failed to fetch sprints for project ${projectKey}: ${(error as Error).message}`,
335				);
336			}
337		}
338	}
