1	import { Processor, WorkerHost, OnWorkerEvent } from '@nestjs/bullmq';
2	import { Logger } from '@nestjs/common';
3	import { Job } from 'bullmq';
4	
5	import { JiraSyncService } from '@modules/jira/jira-sync.service';
6	import {
7		IDiscoverProjectsJob,
8		IPollInstallationsJob,
9		ISyncProjectJob,
10	} from '@modules/jira/types/jira-sync.interface';
11	
12	@Processor('jira')
13	export class JiraProcessor extends WorkerHost {
14		private readonly logger = new Logger(JiraProcessor.name);
15	
16		constructor(private readonly syncService: JiraSyncService) {
17			super();
18		}
19	
20		// eslint-disable-next-line custom-rules/require-object-params
21		async process(
22			job: Job<IDiscoverProjectsJob | ISyncProjectJob | IPollInstallationsJob>,
23		): Promise<void> {
24			try {
25				if (job.name === 'poll_installations') {
26					await this.syncService.pollAllInstallations();
27					return;
28				}
29	
30				if (job.name === 'discover_projects') {
31					const data = job.data as IDiscoverProjectsJob;
32					await this.syncService.discoverProjects({
33						installationDbId: data.installationDbId,
34					});
35					return;
36				}
37	
38				if (job.name === 'sync_project') {
39					const data = job.data as ISyncProjectJob;
40					await this.syncService.syncProject({
41						installationDbId: data.installationDbId,
42						projectDbId: data.projectDbId,
43						projectKey: data.projectKey,
44					});
45					return;
46				}
47	
48				this.logger.warn(`Unknown job type: ${job.name}`);
49			} catch (error) {
50				this.logger.error(
51					`Job ${job.name} (${job.id}) failed: ${(error as Error).message}`,
52				);
53				throw error;
54			}
55		}
56	
57		@OnWorkerEvent('completed')
58		onCompleted({ id, name }: Job): void {
59			this.logger.debug(`Job ${name} (${id}) completed`);
60		}
61	}
