import { randomUUID } from 'crypto';

import fastifyCookie from '@fastify/cookie';
import { HttpService } from '@nestjs/axios';
import { ValidationPipe } from '@nestjs/common';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Test, TestingModule } from '@nestjs/testing';
import { Redis } from 'ioredis';
import Knex from 'knex';
import * as request from 'supertest';

import { AppModule } from '@modules/app/app.module';
import { REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import { JiraProcessor } from '@modules/jira/jira-processor.service';
import { JiraSyncService } from '@modules/jira/jira-sync.service';
import {
	IJiraInstallationBase,
	JiraInstallationStatus,
} from '@modules/jira/types/jira-installation.interface';

import type { App } from 'supertest/types';

import {
	cleanDatabase,
	cleanRedis,
	createAccessToken,
	createSession,
	createTestUser,
	insertCompany,
	insertCompanyMember,
	insertUser,
} from './helpers/auth.helper';

async function cleanJiraTables({ knex }: { knex: Knex.Knex }): Promise<void> {
	await knex.raw('TRUNCATE TABLE jira_installations CASCADE');
}

function makeTokenResponse(overrides: Partial<Record<string, unknown>> = {}): object {
	return {
		data: {
			access_token: 'mock-access-token',
			refresh_token: 'mock-refresh-token',
			expires_in: 3600,
			token_type: 'Bearer',
			scope: 'read:jira-work',
			...overrides,
		},
		status: 200,
		statusText: 'OK',
		headers: {},
		config: { headers: {} as never },
	};
}

function makeResourcesResponse(overrides: Partial<Record<string, unknown>> = {}): object {
	return {
		data: [
			{
				id: 'test-cloud-id',
				url: 'https://test.atlassian.net',
				name: 'Test Site',
				scopes: ['read:jira-work'],
				avatarUrl: '',
				...overrides,
			},
		],
		status: 200,
		statusText: 'OK',
		headers: {},
		config: { headers: {} as never },
	};
}

async function setupAdminUser({
	knex,
	redis,
}: {
	knex: Knex.Knex;
	redis: Redis;
}): Promise<{ accessToken: string; companyId: string; userId: string }> {
	const user = createTestUser({ email: `jira-admin-${randomUUID()}@example.com` });
	await insertUser({ knex, user });

	const company = await insertCompany({ knex, name: `Jira Test Co ${randomUUID()}` });
	await insertCompanyMember({
		knex,
		userId: user._id,
		companyId: company._id,
		role: 'admin',
	});

	const sessionId = randomUUID();
	await createSession({
		redis,
		userId: user._id,
		sessionId,
		role: 'admin',
		companyId: company._id,
	});

	const accessToken = createAccessToken({
		userId: user._id,
		sessionId,
		role: 'admin',
		companyId: company._id,
	});

	return { accessToken, companyId: company._id, userId: user._id };
}

async function createTestInstallation({
	installationModel,
	companyId,
	expiresInFuture = true,
}: {
	installationModel: JiraInstallationModel;
	companyId: string;
	expiresInFuture?: boolean;
}): Promise<IJiraInstallationBase> {
	const tokenExpiresAt = expiresInFuture
		? new Date(Date.now() + 60 * 60 * 1000)
		: new Date(Date.now() - 60 * 60 * 1000);

	return installationModel.create({
		data: {
			company_id: companyId,
			cloud_id: 'test-cloud-id',
			site_url: 'https://test.atlassian.net',
			access_token: 'valid-access-token',
			refresh_token: 'valid-refresh-token',
			token_expires_at: tokenExpiresAt,
		},
	});
}

describe('JiraModule (e2e)', () => {
	let app: NestFastifyApplication;
	let httpServer: App;
	let knex: Knex.Knex;
	let redis: Redis;
	let moduleFixture: TestingModule;
	let installationModel: JiraInstallationModel;
	let projectModel: JiraProjectModel;
	let httpService: HttpService;
	let jiraApiService: JiraApiService;
	let jiraSyncService: JiraSyncService;
	let jiraProcessor: JiraProcessor;

	beforeAll(async () => {
		moduleFixture = await Test.createTestingModule({
			imports: [AppModule],
		}).compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(
			new FastifyAdapter(),
		);
		await app.register(fastifyCookie);

		app.useGlobalPipes(
			new ValidationPipe({
				transform: true,
				whitelist: true,
				forbidNonWhitelisted: true,
			}),
		);

		app.setGlobalPrefix('api', { exclude: ['liveness', 'readiness'] });

		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		httpServer = app.getHttpServer() as App;

		knex = Knex({
			client: 'pg',
			connection: process.env['DATABASE_URL']!,
		});

		redis = moduleFixture.get<Redis>(REDIS_WRITE_CLIENT);
		httpService = moduleFixture.get<HttpService>(HttpService);
		installationModel = moduleFixture.get<JiraInstallationModel>(JiraInstallationModel);
		projectModel = moduleFixture.get<JiraProjectModel>(JiraProjectModel);
		jiraApiService = moduleFixture.get<JiraApiService>(JiraApiService);
		jiraSyncService = moduleFixture.get<JiraSyncService>(JiraSyncService);
		jiraProcessor = moduleFixture.get<JiraProcessor>(JiraProcessor);

		await knex.migrate.latest({ directory: './src/migrations' });
	});

	afterAll(async () => {
		await cleanDatabase({ knex });
		await cleanJiraTables({ knex });
		await cleanRedis({ redis });
		await knex.destroy();
		await app.close();
	});

	beforeEach(async () => {
		await cleanDatabase({ knex });
		await cleanJiraTables({ knex });
		await cleanRedis({ redis });
		jest.restoreAllMocks();
	});

	describe('POST /api/integrations/jira/connect', () => {
		it('should return 200 with Atlassian OAuth URL for admin user', async () => {
			const { accessToken } = await setupAdminUser({ knex, redis });

			const res = await request(httpServer)
				.post('/api/integrations/jira/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(200);
			expect(res.body).toHaveProperty('url');
			expect(res.body.url).toContain('https://auth.atlassian.com/authorize');
			expect(res.body.url).toContain('client_id=');
			expect(res.body.url).toContain('state=');
			expect(res.body.url).toContain('response_type=code');
		});

		it('should return 401 when unauthenticated', async () => {
			const res = await request(httpServer)
				.post('/api/integrations/jira/connect')
				.send();

			expect(res.status).toBe(401);
		});

		it('should return 403 when user has member role', async () => {
			const user = createTestUser({ email: `jira-member-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Member Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'member',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const res = await request(httpServer)
				.post('/api/integrations/jira/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(403);
		});
	});

	describe('GET /api/integrations/jira/callback', () => {
		it('should redirect to success page when callback is valid', async () => {
			const { accessToken } = await setupAdminUser({ knex, redis });

			const connectRes = await request(httpServer)
				.post('/api/integrations/jira/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(connectRes.status).toBe(200);
			const connectUrl = connectRes.body.url as string;
			const state = new URL(connectUrl).searchParams.get('state')!;

			jest
				.spyOn(httpService.axiosRef, 'post')
				.mockResolvedValueOnce(makeTokenResponse());

			jest
				.spyOn(httpService.axiosRef, 'get')
				.mockResolvedValueOnce(makeResourcesResponse());

			const res = await request(httpServer)
				.get('/api/integrations/jira/callback')
				.set('Authorization', `Bearer ${accessToken}`)
				.query({ code: 'test-auth-code', state })
				.redirects(0);

			expect(res.status).toBe(302);
			expect(res.headers['location']).toContain('/settings/integrations');
			expect(res.headers['location']).toContain('connected=jira');

			await new Promise<void>((resolve) => setTimeout(resolve, 200));

			const installations = await knex('jira_installations').select('*');
			expect(installations).toHaveLength(1);
			expect(installations[0].cloud_id).toBe('test-cloud-id');
			expect(installations[0].status).toBe(JiraInstallationStatus.ACTIVE);
		});

		it('should redirect to error page when state is invalid', async () => {
			const { accessToken } = await setupAdminUser({ knex, redis });

			const res = await request(httpServer)
				.get('/api/integrations/jira/callback')
				.set('Authorization', `Bearer ${accessToken}`)
				.query({ code: 'test-code', state: 'invalid-state-that-does-not-exist' })
				.redirects(0);

			expect(res.status).toBe(302);
			expect(res.headers['location']).toContain('error=jira_connect_failed');
		});

		it('should redirect to error page when no accessible resources returned', async () => {
			const { accessToken } = await setupAdminUser({ knex, redis });

			const connectRes = await request(httpServer)
				.post('/api/integrations/jira/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			const connectUrl = connectRes.body.url as string;
			const state = new URL(connectUrl).searchParams.get('state')!;

			jest
				.spyOn(httpService.axiosRef, 'post')
				.mockResolvedValueOnce(makeTokenResponse());

			jest.spyOn(httpService.axiosRef, 'get').mockResolvedValueOnce({
				data: [],
				status: 200,
				statusText: 'OK',
				headers: {},
				config: { headers: {} as never },
			});

			const res = await request(httpServer)
				.get('/api/integrations/jira/callback')
				.set('Authorization', `Bearer ${accessToken}`)
				.query({ code: 'test-code', state })
				.redirects(0);

			expect(res.status).toBe(302);
			expect(res.headers['location']).toContain('error=jira_connect_failed');
		});
	});

	describe('DELETE /api/integrations/jira/installations/:id', () => {
		it('should return 204 on successful disconnect', async () => {
			const { accessToken, companyId } = await setupAdminUser({ knex, redis });

			const installation = await createTestInstallation({ installationModel, companyId });

			const res = await request(httpServer)
				.delete(`/api/integrations/jira/installations/${installation._id}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(204);

			const updated = await knex('jira_installations').where({ _id: installation._id }).first();
			expect(updated?.status).toBe(JiraInstallationStatus.UNINSTALLED);
		});

		it('should return 404 when installation does not exist', async () => {
			const { accessToken } = await setupAdminUser({ knex, redis });
			const nonExistentId = randomUUID();

			const res = await request(httpServer)
				.delete(`/api/integrations/jira/installations/${nonExistentId}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(404);
		});

		it('should return 404 when installation belongs to a different company', async () => {
			const { accessToken } = await setupAdminUser({ knex, redis });

			const otherCompany = await insertCompany({ knex, name: `Other Co ${randomUUID()}` });
			const installation = await createTestInstallation({
				installationModel,
				companyId: otherCompany._id,
			});

			const res = await request(httpServer)
				.delete(`/api/integrations/jira/installations/${installation._id}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(404);
		});

		it('should return 401 when unauthenticated', async () => {
			const res = await request(httpServer)
				.delete('/api/integrations/jira/installations/some-id')
				.send();

			expect(res.status).toBe(401);
		});
	});

	describe('JiraApiService direct tests', () => {
		describe('getValidToken', () => {
			it('should return existing token when it has not expired', async () => {
				const { companyId } = await setupAdminUser({ knex, redis });
				const installation = await createTestInstallation({
					installationModel,
					companyId,
					expiresInFuture: true,
				});

				const postSpy = jest.spyOn(httpService.axiosRef, 'post');
				const token = await jiraApiService.getValidToken({ installation });

				expect(token).toBe('valid-access-token');
				expect(postSpy).not.toHaveBeenCalled();
			});

			it('should refresh token when it has expired', async () => {
				const { companyId } = await setupAdminUser({ knex, redis });
				const installation = await createTestInstallation({
					installationModel,
					companyId,
					expiresInFuture: false,
				});

				jest.spyOn(httpService.axiosRef, 'post').mockResolvedValueOnce(
					makeTokenResponse({ access_token: 'refreshed-token', expires_in: 7200 }),
				);

				const token = await jiraApiService.getValidToken({ installation });

				expect(token).toBe('refreshed-token');
				expect(httpService.axiosRef.post).toHaveBeenCalledWith(
					'https://auth.atlassian.com/oauth/token',
					expect.objectContaining({ grant_type: 'refresh_token' }),
				);
			});

			it('should mark installation as needs_reauth when refresh fails', async () => {
				const { companyId } = await setupAdminUser({ knex, redis });
				const installation = await createTestInstallation({
					installationModel,
					companyId,
					expiresInFuture: false,
				});

				jest
					.spyOn(httpService.axiosRef, 'post')
					.mockRejectedValueOnce(new Error('Token refresh failed'));

				await expect(jiraApiService.getValidToken({ installation })).rejects.toThrow(
