							status: { name: 'In Progress' },
							priority: { name: 'Medium' },
							assignee: { accountId: 'user-a' },
							reporter: { accountId: 'user-b' },
							customfield_10016: 5,
							resolutiondate: null,
							created: '2024-01-01T00:00:00.000Z',
							updated: '2024-01-01T00:00:00.000Z',
						},
						changelog: {
							histories: [
								{
									id: 'hist-null-author',
									author: null,
									created: '2024-01-05T10:00:00.000Z',
									items: [{ field: 'status', fromString: 'Open', toString: 'In Progress' }],
								},
							],
						},
					},
				],
				total: 1,
				startAt: 0,
				maxResults: 100,
			});

			jest.spyOn(jiraApiService, 'getWorklogsForIssue').mockResolvedValueOnce([
				{
					id: 'wl-null-author',
					author: null,
					timeSpentSeconds: 900,
					started: '2024-01-05T09:00:00.000Z',
					created: '2024-01-05T09:00:00.000Z',
					updated: '2024-01-05T09:00:00.000Z',
				},
			]);

			jest.spyOn(jiraApiService, 'listBoards').mockResolvedValueOnce({
				values: [],
				isLast: true,
			});

			await jiraSyncService.syncProject({
				installationDbId: installation._id,
				projectDbId: project._id,
				projectKey: 'PMISS',
			});

			const changelogs = await knex('jira_changelog').select('*');
			expect(changelogs.length).toBeGreaterThanOrEqual(1);
			expect(changelogs[0]!.author_id).toBeNull();

			const worklogs = await knex('jira_worklogs').select('*');
			expect(worklogs.length).toBeGreaterThanOrEqual(1);
			expect(worklogs[0]!.author_id).toBeNull();
		});

		it('should paginate through sprint pages (covers startAt += 50 branch)', async () => {
			const { companyId } = await setupAdminUser({ knex, redis });
			const installation = await createTestInstallation({ installationModel, companyId });

			await projectModel.upsertMany({
				installationId: installation._id,
				projects: [
					{ id: 'proj-pag', key: 'PPAG', name: 'Pagination Project', projectTypeKey: 'software' },
				],
			});

			const projects = await projectModel.findByInstallationId({
				installationId: installation._id,
			});
			const project = projects[0]!;

			jest.spyOn(jiraApiService, 'getValidToken').mockResolvedValue('valid-token');
			jest.spyOn(jiraApiService, 'searchIssues').mockResolvedValueOnce({
				issues: [],
				total: 0,
				startAt: 0,
				maxResults: 100,
			});

			jest.spyOn(jiraApiService, 'listBoards').mockResolvedValueOnce({
				values: [{ id: 99, name: 'Sprint Board', type: 'scrum' }],
				isLast: true,
			});

			const listSprintsSpy = jest.spyOn(jiraApiService, 'listSprints');
			listSprintsSpy.mockResolvedValueOnce({
				values: [{ id: 101, name: 'Sprint A', state: 'closed' }],
				isLast: false,
			});
			listSprintsSpy.mockResolvedValueOnce({
				values: [{ id: 102, name: 'Sprint B', state: 'active' }],
				isLast: true,
			});

			await jiraSyncService.syncProject({
				installationDbId: installation._id,
				projectDbId: project._id,
				projectKey: 'PPAG',
			});

			expect(listSprintsSpy).toHaveBeenCalledTimes(2);
			const sprints = await knex('jira_sprints').select('*');
			expect(sprints).toHaveLength(2);
		});

		it('should handle issue pagination when total exceeds page size', async () => {
			const { companyId } = await setupAdminUser({ knex, redis });
			const installation = await createTestInstallation({ installationModel, companyId });

			await projectModel.upsertMany({
				installationId: installation._id,
				projects: [
					{ id: 'proj-ipag', key: 'PIPAG', name: 'Issue Pag Project', projectTypeKey: 'software' },
				],
			});

			const projects = await projectModel.findByInstallationId({
				installationId: installation._id,
			});
			const project = projects[0]!;

			jest.spyOn(jiraApiService, 'getValidToken').mockResolvedValue('valid-token');

			const makeIssues = (count: number, startId: number): typeof searchResult.issues =>
				Array.from({ length: count }, (_, i) => ({
					id: `issue-p-${startId + i}`,
					key: `PIPAG-${startId + i}`,
					fields: {
						summary: `Issue ${startId + i}`,
						issuetype: { name: 'Task' },
						status: { name: 'Open' },
						priority: null,
						assignee: null,
						reporter: null,
						customfield_10016: null,
						resolutiondate: null,
						created: '2024-01-01T00:00:00.000Z',
						updated: '2024-01-01T00:00:00.000Z',
					},
				}));

			const searchResult = {
				issues: makeIssues(100, 1),
				total: 101,
				startAt: 0,
				maxResults: 100,
			};

			const searchSpy = jest.spyOn(jiraApiService, 'searchIssues');
			searchSpy.mockResolvedValueOnce(searchResult);
			searchSpy.mockResolvedValueOnce({
				issues: makeIssues(1, 101),
				total: 101,
				startAt: 100,
				maxResults: 100,
			});

			jest.spyOn(jiraApiService, 'getWorklogsForIssue').mockResolvedValue([]);
			jest.spyOn(jiraApiService, 'listBoards').mockResolvedValueOnce({
				values: [],
				isLast: true,
			});

			await jiraSyncService.syncProject({
				installationDbId: installation._id,
				projectDbId: project._id,
				projectKey: 'PIPAG',
			});

			expect(searchSpy).toHaveBeenCalledTimes(2);
		});

		it('should handle empty sprint values in pagination (covers empty sprint values break)', async () => {
			const { companyId } = await setupAdminUser({ knex, redis });
			const installation = await createTestInstallation({ installationModel, companyId });

			await projectModel.upsertMany({
				installationId: installation._id,
				projects: [
					{ id: 'proj-espag', key: 'PESPAG', name: 'Empty Sprint Pag', projectTypeKey: 'software' },
				],
			});

			const projects = await projectModel.findByInstallationId({
				installationId: installation._id,
			});
			const project = projects[0]!;

			jest.spyOn(jiraApiService, 'getValidToken').mockResolvedValue('valid-token');
			jest.spyOn(jiraApiService, 'searchIssues').mockResolvedValueOnce({
				issues: [],
				total: 0,
				startAt: 0,
				maxResults: 100,
			});
			jest.spyOn(jiraApiService, 'listBoards').mockResolvedValueOnce({
				values: [{ id: 200, name: 'Empty Board', type: 'scrum' }],
				isLast: true,
			});
			jest.spyOn(jiraApiService, 'listSprints').mockResolvedValueOnce({
				values: [],
				isLast: false,
			});

			await jiraSyncService.syncProject({
				installationDbId: installation._id,
				projectDbId: project._id,
				projectKey: 'PESPAG',
			});

			const sprints = await knex('jira_sprints').select('*');
			expect(sprints).toHaveLength(0);
		});
	});
});

